'use client';

interface FormStepperProps {
  currentStep: number;
  totalSteps: number;
}

const steps = [
  { number: 1, label: 'Negocio' },
  { number: 2, label: 'Mercado' },
  { number: 3, label: 'Cliente' },
  { number: 4, label: 'Competencia' },
  { number: 5, label: 'Objetivos' },
  { number: 6, label: 'Dolores' },
  { number: 7, label: 'Contacto' },
];

export default function FormStepper({ currentStep, totalSteps }: FormStepperProps) {
  return (
    <div className="w-full mb-16">
      {/* Progress text */}
      <div className="mb-8 text-center">
        <p className="text-sm font-semibold text-[#2d6cff] tracking-wide uppercase mb-2">Progreso</p>
        <p className="text-lg font-bold text-[#0b1530]">
          Paso <span className="text-[#2d6cff]">{currentStep}</span> de <span>{totalSteps}</span>
        </p>
      </div>

      {/* Horizontal stepper */}
      <div className="flex items-center justify-center gap-1 sm:gap-2">
        {steps.map((step, index) => (
          <div key={step.number} className="flex items-center flex-1 max-w-sm">
            {/* Step circle */}
            <div className="flex flex-col items-center flex-shrink-0 w-full">
              <div
                className={`w-12 h-12 rounded-full flex items-center justify-center font-bold text-sm transition-all duration-300 flex-shrink-0 ${
                  step.number < currentStep
                    ? 'bg-[#2d6cff] text-white shadow-lg'
                    : step.number === currentStep
                    ? 'bg-white border-2 border-[#2d6cff] text-[#2d6cff] shadow-lg'
                    : 'bg-[#f0f4f9] border-2 border-[#e4e9f1] text-[#94a3b8]'
                }`}
              >
                {step.number < currentStep ? (
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                  </svg>
                ) : (
                  step.number
                )}
              </div>
              <p className="text-xs font-semibold text-[#64748b] mt-2 text-center">
                {step.label}
              </p>
            </div>

            {/* Connector line */}
            {index < steps.length - 1 && (
              <div className={`h-1 flex-1 mx-2 transition-colors duration-300 ${
                step.number < currentStep ? 'bg-[#2d6cff]' : 'bg-[#e4e9f1]'
              }`} />
            )}
          </div>
        ))}
      </div>

      {/* Progress bar under stepper */}
      <div className="mt-8">
        <div className="h-2 bg-[#f0f4f9] rounded-full overflow-hidden shadow-sm">
          <div
            className="h-full bg-gradient-to-r from-[#2d6cff] to-[#1f4fd1] transition-all duration-500"
            style={{ width: `${(currentStep / totalSteps) * 100}%` }}
          />
        </div>
      </div>
    </div>
  );
}
